    def predict(self, X):
        if self.weights is None:
            raise ValueError("Call fit before predict")
        X = self._augment(X)
        return X @ self.weights

    def _augment(self, X):
        X = np.asarray(X, dtype=float)
        bias = np.ones((X.shape[0], 1))
        return np.hstack([bias, X])
